public class Solution {
    public static void main(String[] args) {
        int result = getGCD(24, 18);
        System.out.println(result);
    }

    // Complete the GCD method below:
    public static int getGCD(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }
}
